import React, { useEffect, useState } from 'react'
import AceEditor from "react-ace";
import "ace-builds/src-noconflict/mode-html";
import 'ace-builds/src-noconflict/snippets/html'
import "ace-builds/src-noconflict/ace";
import 'ace-builds/src-noconflict/theme-github'
import "ace-builds/src-noconflict/ext-spellcheck";
import "ace-builds/src-noconflict/ext-language_tools";
import HtmlEditorStyle from './HtmlEditorStyle.js'
import { Button, Space, Tag } from 'antd';
import { CloseOutlined, QuestionCircleOutlined } from '@ant-design/icons';
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import CodeEditorIcon from '../../images/code_editor_icon.svg'
import CodePreviewIcon from '../../images/code_preview_icon.svg'
import CustomModal from './CustomModal';
import { saveLabelTemplateScript } from "../APIConfig/LabelTemplateAction";
import { isEmpty, toUpper } from 'lodash';
import { DATA_INDEX, OPERATIONS, STATUS } from '../../utils/constants';
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';

const containerConstants = containerConstantsService.getInstance();

const HtmlEditor = ({ showEditor, setShowEditor, setShowTable, updateTemplateStatus }) => {

    const [htmlContent, setHtmlContent] = useState("");
    const [srcDoc, setSrcDoc] = useState("");
    const [ispublishButtonEnabled, setIspublishButtonEnabled] = useState(false);
    const [isDataChanges, setIsDataChanges] = useState(false);
    const [showHelpModal, setShowHelpModal] = useState(false);


    useEffect(() => {
        const timerId = setTimeout(() => { setSrcDoc(htmlContent) }, 250);
        return () => clearTimeout(timerId);
    }, [htmlContent])

    useEffect(() => {
        if (showEditor.operationType === OPERATIONS.EDIT) {
            setHtmlContent(showEditor.script ? showEditor.script : " ");
            if(showEditor[DATA_INDEX.TEMPLATE_STATUS] ===  STATUS.INPROGRESS){
                setIspublishButtonEnabled(true);
            }
            setSrcDoc(showEditor.script);
        }

    }, [showEditor])

    const onSaveScript = () => {
        const templateScriptReqObj = { [DATA_INDEX.TEMPLATE_ID]: showEditor[DATA_INDEX.TEMPLATE_ID], [DATA_INDEX.TEMPLATE_SCRIPT]: srcDoc };
        if (!isEmpty(srcDoc)) {
            saveLabelTemplateScript(templateScriptReqObj)
                .then(response => {
                    if (response && response.status === 200) {
                        if (toUpper(response.data?.status) === STATUS.SUCCESS) {
                            setIsDataChanges(false);
                            notifyResponseMessage(STATUS.SUCCESS, response?.data?.message);
                            setIspublishButtonEnabled(true);
                        }else{
                            notifyResponseMessage(STATUS.ERROR, response?.data?.message);

                        }
                    }
                })
                .catch(error => {

                });
        }

    }

    const onPublishTemplate = async () => {

        if (ispublishButtonEnabled) {

            const publishTemplateReqObj = {
                [DATA_INDEX.TEMPLATE_ID]: showEditor[DATA_INDEX.TEMPLATE_ID],
                [DATA_INDEX.IS_ACTIVE]: true,
            };

            if (toUpper(await updateTemplateStatus(null, publishTemplateReqObj)) === STATUS.SUCCESS) {
                setIspublishButtonEnabled(false);
                handleClickCancel();
            }
        }
    }

    const handleClickCancel = () => {
        setShowEditor({ visible: false });
        setShowTable(true);
        setSrcDoc("");
        setHtmlContent(" ");
        setIspublishButtonEnabled(false);
        setIsDataChanges(false);

    }

    return (
        <div>
            <HtmlEditorStyle/>
            <CustomModal {...{ showHelpModal, setShowHelpModal }} />
            <div className='html-editor' style={{ display: showEditor.visible ? 'block' : 'none' }}>
                <div className='editor-container'>
                    <div className='editor-nav'>
                        <span className='editor-nav-title' >{showEditor[DATA_INDEX.TEMPLATE_NAME]}</span>
                        <Tag className={'fw400 fs12 status-tag' + (showEditor[DATA_INDEX.TEMPLATE_STATUS] === STATUS.ACTIVE ? ' status-tag-active' : ' status-tag-draft')} color={(showEditor[DATA_INDEX.TEMPLATE_STATUS] === STATUS.ACTIVE) ? '#E2FFEA' : '#F3F3F3'}>{containerConstants.formatString(containerConstants[showEditor[DATA_INDEX.TEMPLATE_STATUS]])}</Tag>
                        <div className='editor-nav-btn'>
                            <Space size={8} align='end'>
                                <Button size='small' className='fw400 fs14 lh22 action-btn' ghost type='primary' disabled = {!ispublishButtonEnabled} onClick={onPublishTemplate}>
                                    {containerConstants.formatString(containerConstants.PUBLISH)}
                                </Button>
                                <Button size='small' disabled = {!isDataChanges} className='fw400 fs14 lh22 action-btn' type='primary' style={{ color: '#FFFFFF' }} onClick={onSaveScript}>
                                    {containerConstants.formatString(containerConstants.SAVE)}
                                </Button>
                            </Space>
                            <Button size='small' className='border-none' style={{ marginLeft: '20px' }} onClick={handleClickCancel} icon={<CloseOutlined style={{ fontSize: '14px', color: '#323232' }} />} />
                        </div>
                    </div>
                    <div className='editor-body'>
                        <div className='html-code-editor'>
                            <div className='editor-sub-header flex justify-space-btw'>
                                <span className='title-section flex'>
                                    <img alt ='' src={CodeEditorIcon} />
                                    <span className='title fw400 fs12 lh18'>{containerConstants.formatString(containerConstants.HTML_EDITOR)}</span>
                                </span>
                                <span className='help-section flex pointer' onClick={() => setShowHelpModal({
                                    visible: true,
                                    title: containerConstants.formatString(containerConstants.HELP_DOCUMENT),
                                })}>
                                    <QuestionCircleOutlined style={{ fontSize: '15px' }} />
                                    <span className='title fw400 fs12 lh18'>{containerConstants.formatString(containerConstants.HELP)}</span>
                                </span>
                            </div>
                            <AceEditor
                                mode="html"
                                theme="github"
                                name="HTML_EDITOR"
                                onChange={(value) => {
                                    setIsDataChanges(true);
                                    setHtmlContent(value);
                                }}
                                style={{ width: '95%', height: '88%', zIndex : 0 }}
                                className='html-code-editor-container'
                                fontSize={13}
                                showPrintMargin={true}
                                showGutter={true}
                                highlightActiveLine={false}
                                value={htmlContent}
                                wrapEnabled={false}
                                setOptions={{
                                    enableBasicAutocompletion: true,
                                    enableLiveAutocompletion: true,
                                    enableSnippets: true,
                                    showLineNumbers: true,
                                    tabSize: 2,
                                    spellcheck: true,
                                    useWorker: true
                                }}
                            />
                        </div>
                        <div className='html-code-preview'>
                            <div className='editor-sub-header flex'>
                                <span className='title-section flex'>
                                    <img alt ='' src={CodePreviewIcon} />
                                    <span className='title fw400 fs12 lh18'>{containerConstants.formatString(containerConstants.HTML_PREVIEW)}</span>
                                </span>
                            </div>
                            <div className='html-code-preview-container' >
                                <iframe
                                    srcDoc={srcDoc}
                                    width={'100%'}
                                    height={'486px'}
                                    frameBorder={0}
                                    sandbox='allow-scripts'
                                />
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default HtmlEditor
